css:
.tn-header {
  margin-bottom: 3mm;
}
.tn-title {
  font-weight: 700;
  font-size: 11pt;
  margin: 0;
}
.tn-meta {
  color: #555;
  font-size: 7.5pt;
  margin-top: 0.4mm;
}
.tn-meta .sep {
  color: #aaa;
  padding: 0 1mm;
}
.tn-bemerkung {
  margin-top: 1.2mm;
  font-size: 7.5pt;
  color: #333;
  font-style: italic;
}
.tn-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 7pt;
  line-height: 1.1;
}
.tn-table th {
  text-align: left;
  font-size: 6.5pt;
  color: #555;
  text-transform: uppercase;
  letter-spacing: 0.2px;
  border-bottom: 1px solid #333;
  padding: 0.6mm 1mm;
  font-weight: 600;
}
.tn-table td {
  padding: 0.4mm 1mm;
  vertical-align: middle;
  border-bottom: 1px solid #bbb;
}
.tn-table tr.eintrag-row {
  break-inside: avoid;
}
.tn-wohnung-id {
  font-weight: 700;
  font-size: 8pt;
  text-align: right;
  color: #111;
  white-space: nowrap;
  padding-right: 1.5mm;
}
.tn-wohnung {
  font-weight: 600;
  white-space: nowrap;
  font-size: 7pt;
}
.tn-imm {
  color: #888;
  font-size: 6pt;
  font-weight: 400;
  margin-left: 1.2mm;
}
.tn-mieter {
  font-weight: 500;
}
.tn-mieter-sep {
  color: #aaa;
  padding: 0 0.5mm;
}
.tn-rolle {
  color: #888;
  font-size: 6pt;
  margin-left: 0.4mm;
}
.tn-phone-row {
  white-space: nowrap;
}
.tn-phone-label {
  color: #999;
  font-size: 6pt;
  margin-right: 0.3mm;
}
.tn-phone-sep {
  color: #ccc;
  padding: 0 0.8mm;
}
.tn-phone-name {
  color: #555;
  font-size: 6pt;
  margin-right: 0.4mm;
}
.tn-empty {
  color: #bbb;
}

html:
{%- set groups = doc.get_grouped_eintraege() -%}
{%- set show_immobilie = not doc.immobilie -%}
{%- set anzahl_eintraege = doc.eintraege|length -%}

<div class="tn-header">
  <h1 class="tn-title">{{ doc.titel or _("Telefonnummern Mieter") }}</h1>
  <div class="tn-meta">
    {{ _("Stichtag") }}: {{ frappe.utils.formatdate(doc.stichtag) }}
    {%- if doc.immobilie %}
      <span class="sep">·</span>{{ _("Immobilie") }}: {{ doc.immobilie }}
    {%- endif %}
    <span class="sep">·</span>{{ _("Einträge") }}: {{ anzahl_eintraege }}
  </div>
  {%- if doc.bemerkung %}
    <div class="tn-bemerkung">{{ doc.bemerkung }}</div>
  {%- endif %}
</div>

{%- if not groups %}
  <p class="tn-empty">{{ _("Keine Einträge vorhanden. Bitte im Formular auf \"Einträge laden\" klicken.") }}</p>
{%- else %}
  <table class="tn-table">
    <thead>
      <tr>
        <th style="width: 6%; text-align: right;">{{ _("ID") }}</th>
        <th style="width: 22%">{{ _("Wohnung") }}</th>
        <th style="width: 30%">{{ _("Mieter") }}</th>
        <th style="width: 42%">{{ _("Telefon / Mobil") }}</th>
      </tr>
    </thead>
    <tbody>
      {%- for grp in groups %}
        {%- set multi = grp.mieter|length > 1 -%}
        <tr class="eintrag-row">
          <td class="tn-wohnung-id">{{ grp.wohnung_id if grp.wohnung_id is not none else '' }}</td>
          <td class="tn-wohnung">
            {{ grp.wohnung }}
            {%- if show_immobilie and grp.immobilie %}
              <span class="tn-imm">{{ grp.immobilie }}{% if grp.gebaeudeteil %} · {{ grp.gebaeudeteil }}{% endif %}</span>
            {%- elif grp.gebaeudeteil %}
              <span class="tn-imm">{{ grp.gebaeudeteil }}</span>
            {%- endif %}
          </td>
          <td>
            {%- for m in grp.mieter -%}
              {%- if not loop.first %}<span class="tn-mieter-sep">·</span>{% endif -%}
              <span class="tn-mieter">{{ m.name }}</span>
              {%- if m.rolle and m.rolle != 'Hauptmieter' %}<span class="tn-rolle">({{ m.rolle }})</span>{% endif -%}
            {%- endfor %}
          </td>
          <td>
            {%- for m in grp.mieter -%}
              {%- if not loop.first %}<span class="tn-phone-sep">·</span>{% endif -%}
              <span class="tn-phone-row">
                {%- if multi %}<span class="tn-phone-name">{{ m.name.split(' ')[-1] }}:</span>{% endif -%}
                {%- if m.telefon %}<span class="tn-phone-label">{{ _("T") }}</span>{{ m.telefon }}{% endif -%}
                {%- if m.telefon and m.mobil %} <span class="tn-phone-label">{{ _("M") }}</span>{{ m.mobil }}{% elif m.mobil %}<span class="tn-phone-label">{{ _("M") }}</span>{{ m.mobil }}{% endif -%}
                {%- if not m.telefon and not m.mobil %}<span class="tn-empty">—</span>{% endif -%}
              </span>
            {%- endfor %}
          </td>
        </tr>
      {%- endfor %}
    </tbody>
  </table>
{%- endif %}
